#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char s[200005];
    while (T--) {
        scanf("%s", s);
        int n = strlen(s);
        int carry = 1;
        for (int i = n - 1; i >= 0 && carry; --i) {
            int d = s[i] - '0' + carry;
            s[i] = (d % 10) + '0';
            carry = d / 10;
        }
        if (carry) {
            // need to shift right by one position
            memmove(s + 1, s, n + 1); // include terminating '\0'
            s[0] = '1';
        }
        printf("%s\n", s);
    }
    return 0;
}

