import sys

def add_one(num: str) -> str:
    lst = list(num)
    i = len(lst) - 1
    carry = 1
    while i >= 0 and carry:
        d = ord(lst[i]) - 48 + carry
        lst[i] = chr(48 + d % 10)
        carry = d // 10
        i -= 1
    if carry:
        lst.insert(0, '1')
    return ''.join(lst)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        out.append(add_one(data[idx]))
        idx += 1
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

